// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Build a search query from natural language
	// (POST /agents/query-builder)
	QueryBuilderAgent(w http.ResponseWriter, r *http.Request)
	// Retrieval Agent - Agentic document retrieval with tool calling
	// (POST /agents/retrieval)
	RetrievalAgent(w http.ResponseWriter, r *http.Request)
	// Backup all tables or selected tables
	// (POST /backup)
	Backup(w http.ResponseWriter, r *http.Request)
	// List available backups
	// (GET /backups)
	ListBackups(w http.ResponseWriter, r *http.Request, params ListBackupsParams)
	// Cross-table batch operations
	// (POST /batch)
	MultiBatchWrite(w http.ResponseWriter, r *http.Request)
	// Standalone evaluation endpoint
	// (POST /eval)
	Evaluate(w http.ResponseWriter, r *http.Request)
	// Perform a global query
	// (POST /query)
	GlobalQuery(w http.ResponseWriter, r *http.Request)
	// Restore multiple tables from a backup
	// (POST /restore)
	Restore(w http.ResponseWriter, r *http.Request)
	// List secrets status
	// (GET /secrets)
	ListSecrets(w http.ResponseWriter, r *http.Request)
	// Delete a secret
	// (DELETE /secrets/{key})
	DeleteSecret(w http.ResponseWriter, r *http.Request, key string)
	// Store a secret
	// (PUT /secrets/{key})
	PutSecret(w http.ResponseWriter, r *http.Request, key string)
	// Get cluster status
	// (GET /status)
	GetStatus(w http.ResponseWriter, r *http.Request)
	// List all tables
	// (GET /tables)
	ListTables(w http.ResponseWriter, r *http.Request, params ListTablesParams)
	// Drop a table
	// (DELETE /tables/{tableName})
	DropTable(w http.ResponseWriter, r *http.Request, tableName string)
	// Get table details
	// (GET /tables/{tableName})
	GetTable(w http.ResponseWriter, r *http.Request, tableName string)
	// Create a new table
	// (POST /tables/{tableName})
	CreateTable(w http.ResponseWriter, r *http.Request, tableName string)
	// Backup a table
	// (POST /tables/{tableName}/backup)
	BackupTable(w http.ResponseWriter, r *http.Request, tableName string)
	// Perform batch inserts and deletes on a table
	// (POST /tables/{tableName}/batch)
	BatchWrite(w http.ResponseWriter, r *http.Request, tableName string)
	// List all indexes for a table
	// (GET /tables/{tableName}/indexes)
	ListIndexes(w http.ResponseWriter, r *http.Request, tableName string)
	// Drop an index from a table
	// (DELETE /tables/{tableName}/indexes/{indexName})
	DropIndex(w http.ResponseWriter, r *http.Request, tableName string, indexName string)
	// Get index details
	// (GET /tables/{tableName}/indexes/{indexName})
	GetIndex(w http.ResponseWriter, r *http.Request, tableName string, indexName string)
	// Add an index to a table
	// (POST /tables/{tableName}/indexes/{indexName})
	CreateIndex(w http.ResponseWriter, r *http.Request, tableName string, indexName string)
	// Scan keys in a table within a key range
	// (POST /tables/{tableName}/lookup)
	ScanKeys(w http.ResponseWriter, r *http.Request, tableName string)
	// Lookup a key in a table
	// (GET /tables/{tableName}/lookup/{key})
	LookupKey(w http.ResponseWriter, r *http.Request, tableName string, key string, params LookupKeyParams)
	// Synchronize data from external sources (Shopify, Postgres, S3) using a linear merge
	// (POST /tables/{tableName}/merge)
	LinearMerge(w http.ResponseWriter, r *http.Request, tableName string)
	// Query a specific table
	// (POST /tables/{tableName}/query)
	QueryTable(w http.ResponseWriter, r *http.Request, tableName string)
	// Restore a table from backup
	// (POST /tables/{tableName}/restore)
	RestoreTable(w http.ResponseWriter, r *http.Request, tableName string)
	// Update a table's schema
	// (PUT /tables/{tableName}/schema)
	UpdateSchema(w http.ResponseWriter, r *http.Request, tableName string)
	// Commit an OCC transaction
	// (POST /transactions/commit)
	CommitTransaction(w http.ResponseWriter, r *http.Request)
}

